import{D as e,d as t,l as n}from"./runtime-core.esm-bundler-BkUJkfAY.js";import{t as r}from"./plugin-vue_export-helper-CwH_LPhl.js";var i=JSON.parse(`{"path":"/%E6%B5%8B%E8%AF%95%E9%9D%A2%E8%AF%95/%E5%9F%BA%E7%A1%80%E9%9D%A2%E8%AF%95%E9%A2%98/","title":"测试基础面试题","lang":"zh-CN","frontmatter":{"title":"测试基础面试题","icon":"question-circle","order":1},"git":{"createdTime":1775224643000,"updatedTime":1775224643000,"contributors":[{"name":"mokylp","username":"mokylp","email":"moklgy@foxmail.com","commits":1,"url":"https://github.com/mokylp"}]},"readingTime":{"minutes":13.15,"words":3945},"filePathRelative":"测试面试/基础面试题/README.md","excerpt":"\\n<p>本文整理了软件测试工程师面试中常见的基础面试题，涵盖测试理论、测试方法、测试流程等方面，帮助准备测试面试。</p>\\n<h2>📚 测试理论</h2>\\n<h3>1. 什么是软件测试？</h3>\\n<div class=\\"language-markdown line-numbers-mode\\" data-highlighter=\\"shiki\\" data-ext=\\"markdown\\" style=\\"background-color:#282c34;color:#abb2bf\\"><pre class=\\"shiki one-dark-pro vp-code\\"><code class=\\"language-markdown\\"><span class=\\"line\\"><span style=\\"color:#ABB2BF\\">软件测试是通过人工或自动化的手段，对软件系统进行验证和确认的过程，目的是发现软件中的缺陷，评估软件质量，确保软件满足需求规格。</span></span>\\n<span class=\\"line\\"></span>\\n<span class=\\"line\\"><span style=\\"color:#D19A66\\">**测试的目的：**</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">1.</span><span style=\\"color:#ABB2BF\\"> 发现软件中的缺陷</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">2.</span><span style=\\"color:#ABB2BF\\"> 验证软件是否满足需求</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">3.</span><span style=\\"color:#ABB2BF\\"> 评估软件质量</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">4.</span><span style=\\"color:#ABB2BF\\"> 提供质量信息，支持决策</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">5.</span><span style=\\"color:#ABB2BF\\"> 预防缺陷</span></span>\\n<span class=\\"line\\"></span>\\n<span class=\\"line\\"><span style=\\"color:#D19A66\\">**测试的原则：**</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">1.</span><span style=\\"color:#ABB2BF\\"> 测试显示缺陷的存在，但不能证明没有缺陷</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">2.</span><span style=\\"color:#ABB2BF\\"> 穷尽测试是不可能的</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">3.</span><span style=\\"color:#ABB2BF\\"> 测试尽早介入</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">4.</span><span style=\\"color:#ABB2BF\\"> 缺陷集群性（二八原则）</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">5.</span><span style=\\"color:#ABB2BF\\"> 杀虫剂悖论</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">6.</span><span style=\\"color:#ABB2BF\\"> 测试活动依赖于测试背景</span></span>\\n<span class=\\"line\\"><span style=\\"color:#E5C07B\\">7.</span><span style=\\"color:#ABB2BF\\"> 不存在缺陷的谬论</span></span></code></pre>\\n<div class=\\"line-numbers\\" aria-hidden=\\"true\\" style=\\"counter-reset:line-number 0\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>"}`),a={name:`README.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="测试基础面试题" tabindex="-1"><a class="header-anchor" href="#测试基础面试题"><span>测试基础面试题</span></a></h1><p>本文整理了软件测试工程师面试中常见的基础面试题，涵盖测试理论、测试方法、测试流程等方面，帮助准备测试面试。</p><h2 id="📚-测试理论" tabindex="-1"><a class="header-anchor" href="#📚-测试理论"><span>📚 测试理论</span></a></h2><h3 id="_1-什么是软件测试" tabindex="-1"><a class="header-anchor" href="#_1-什么是软件测试"><span>1. 什么是软件测试？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#ABB2BF;">软件测试是通过人工或自动化的手段，对软件系统进行验证和确认的过程，目的是发现软件中的缺陷，评估软件质量，确保软件满足需求规格。</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**测试的目的：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#ABB2BF;"> 发现软件中的缺陷</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#ABB2BF;"> 验证软件是否满足需求</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#ABB2BF;"> 评估软件质量</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#ABB2BF;"> 提供质量信息，支持决策</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#ABB2BF;"> 预防缺陷</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**测试的原则：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#ABB2BF;"> 测试显示缺陷的存在，但不能证明没有缺陷</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#ABB2BF;"> 穷尽测试是不可能的</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#ABB2BF;"> 测试尽早介入</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#ABB2BF;"> 缺陷集群性（二八原则）</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#ABB2BF;"> 杀虫剂悖论</span></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#ABB2BF;"> 测试活动依赖于测试背景</span></span>
<span class="line"><span style="color:#E5C07B;">7.</span><span style="color:#ABB2BF;"> 不存在缺陷的谬论</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-软件测试的生命周期是什么" tabindex="-1"><a class="header-anchor" href="#_2-软件测试的生命周期是什么"><span>2. 软件测试的生命周期是什么？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#ABB2BF;">软件测试生命周期（STLC）包括以下阶段：</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **需求分析阶段**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 分析需求文档</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 识别可测试需求</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备需求可追溯性矩阵</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **测试计划阶段**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 制定测试策略</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备测试计划文档</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 估算测试工作量</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 确定测试资源</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **测试设计阶段**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 设计测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备测试数据</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 评审测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 更新需求可追溯性矩阵</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **测试环境搭建**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备测试环境</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 安装测试工具</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 配置测试环境</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **测试执行阶段**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 执行测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 记录测试结果</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 报告缺陷</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 跟踪缺陷状态</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#D19A66;"> **测试结束阶段**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 评估测试完成标准</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备测试报告</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 归档测试资产</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 总结经验教训</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-测试级别有哪些" tabindex="-1"><a class="header-anchor" href="#_3-测试级别有哪些"><span>3. 测试级别有哪些？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**1. 单元测试（Unit Testing）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试对象：单个函数、方法、类</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试人员：开发人员</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试重点：代码逻辑、边界条件</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试工具：JUnit、pytest、unittest</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**2. 集成测试（Integration Testing）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试对象：模块间接口、组件间交互</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试人员：开发人员、测试人员</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试重点：接口正确性、数据传递</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试方法：自顶向下、自底向上、大爆炸</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**3. 系统测试（System Testing）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试对象：完整的软件系统</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试人员：测试人员</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试重点：功能完整性、性能、安全性</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试类型：功能测试、性能测试、安全测试等</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**4. 验收测试（Acceptance Testing）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试对象：完整的软件系统</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试人员：用户、客户、业务人员</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试重点：是否符合业务需求</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 测试类型：用户验收测试（UAT）、Alpha测试、Beta测试</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-测试类型有哪些" tabindex="-1"><a class="header-anchor" href="#_4-测试类型有哪些"><span>4. 测试类型有哪些？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**按测试目的分类：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **功能测试**</span><span style="color:#ABB2BF;">：验证软件功能是否符合需求</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **性能测试**</span><span style="color:#ABB2BF;">：评估系统性能指标</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **安全测试**</span><span style="color:#ABB2BF;">：检查系统安全性</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **兼容性测试**</span><span style="color:#ABB2BF;">：验证在不同环境下的兼容性</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **可用性测试**</span><span style="color:#ABB2BF;">：评估用户体验</span></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#D19A66;"> **回归测试**</span><span style="color:#ABB2BF;">：验证修改后原有功能正常</span></span>
<span class="line"><span style="color:#E5C07B;">7.</span><span style="color:#D19A66;"> **冒烟测试**</span><span style="color:#ABB2BF;">：验证基本功能是否正常</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**按测试方法分类：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **黑盒测试**</span><span style="color:#ABB2BF;">：基于需求和功能，不关心内部实现</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **白盒测试**</span><span style="color:#ABB2BF;">：基于代码内部逻辑和结构</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **灰盒测试**</span><span style="color:#ABB2BF;">：结合黑盒和白盒测试方法</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**按测试阶段分类：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **静态测试**</span><span style="color:#ABB2BF;">：不执行代码的测试（评审、检查）</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **动态测试**</span><span style="color:#ABB2BF;">：执行代码的测试</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="🔧-测试方法" tabindex="-1"><a class="header-anchor" href="#🔧-测试方法"><span>🔧 测试方法</span></a></h2><h3 id="_5-黑盒测试方法有哪些" tabindex="-1"><a class="header-anchor" href="#_5-黑盒测试方法有哪些"><span>5. 黑盒测试方法有哪些？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**1. 等价类划分法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：将输入域划分为有效和无效等价类</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：输入框测试、参数测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 示例：年龄输入框（有效：0-150，无效：负数、&gt;150）</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**2. 边界值分析法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：测试边界值和边界附近的值</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：数值范围测试、数组索引测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 示例：年龄输入框边界值：-1, 0, 1, 149, 150, 151</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**3. 判定表法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：分析输入条件和输出结果的逻辑关系</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：多条件组合的业务逻辑测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 示例：登录功能（用户名、密码、验证码组合）</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**4. 因果图法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：分析输入条件之间的因果关系</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：复杂的业务逻辑测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 步骤：分析因果 → 绘制因果图 → 转换为判定表</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**5. 状态迁移法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：测试系统状态的变化</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：状态机、工作流测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 示例：订单状态（待支付、已支付、已发货、已完成）</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**6. 场景法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：基于用户场景设计测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：业务流程测试、端到端测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 示例：电商购物流程（浏览→加入购物车→下单→支付）</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**7. 错误推测法**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 原理：基于经验和直觉推测可能出错的地方</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 应用：补充其他测试方法</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 示例：异常操作、非法输入、并发操作</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-白盒测试方法有哪些" tabindex="-1"><a class="header-anchor" href="#_6-白盒测试方法有哪些"><span>6. 白盒测试方法有哪些？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**1. 语句覆盖**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：执行程序中的每条语句至少一次</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 覆盖率：语句覆盖率 = 已执行语句数 / 总语句数</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 优点：简单易实现</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 缺点：不能发现逻辑错误</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**2. 判定覆盖（分支覆盖）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：每个判定的真假分支至少执行一次</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 覆盖率：分支覆盖率 = 已执行分支数 / 总分支数</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 优点：比语句覆盖更强</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 缺点：不能发现条件组合错误</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**3. 条件覆盖**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：每个条件的真假值至少执行一次</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 优点：比判定覆盖更细致</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 缺点：不能保证判定覆盖</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**4. 判定-条件覆盖**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：同时满足判定覆盖和条件覆盖</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 优点：结合两者优点</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 缺点：不能发现多条件组合错误</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**5. 条件组合覆盖**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：每个判定中所有条件的可能组合至少执行一次</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 优点：最全面的逻辑覆盖</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 缺点：测试用例数量多</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**6. 路径覆盖**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：执行程序中所有可能的路径</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 优点：最全面的覆盖</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 缺点：对于复杂程序几乎不可能实现</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**7. 基本路径测试**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 目标：基于程序控制流图，测试所有独立路径</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 步骤：绘制控制流图 → 计算圈复杂度 → 确定独立路径 → 设计测试用例</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_7-如何设计测试用例" tabindex="-1"><a class="header-anchor" href="#_7-如何设计测试用例"><span>7. 如何设计测试用例？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**测试用例设计步骤：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **分析需求**</span><span style="color:#ABB2BF;">：理解功能需求和业务逻辑</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **确定测试范围**</span><span style="color:#ABB2BF;">：明确要测试的功能点</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **选择测试方法**</span><span style="color:#ABB2BF;">：根据功能特点选择合适的测试方法</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **设计测试用例**</span><span style="color:#ABB2BF;">：编写详细的测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **评审测试用例**</span><span style="color:#ABB2BF;">：与相关人员评审测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#D19A66;"> **优化测试用例**</span><span style="color:#ABB2BF;">：根据评审意见优化测试用例</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**测试用例要素：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **用例ID**</span><span style="color:#ABB2BF;">：唯一标识符</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **用例标题**</span><span style="color:#ABB2BF;">：简洁明了的描述</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **优先级**</span><span style="color:#ABB2BF;">：P0、P1、P2、P3</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **前置条件**</span><span style="color:#ABB2BF;">：执行测试前需要满足的条件</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **测试步骤**</span><span style="color:#ABB2BF;">：详细的操作步骤</span></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#D19A66;"> **预期结果**</span><span style="color:#ABB2BF;">：期望的输出或行为</span></span>
<span class="line"><span style="color:#E5C07B;">7.</span><span style="color:#D19A66;"> **实际结果**</span><span style="color:#ABB2BF;">：实际测试结果（执行时填写）</span></span>
<span class="line"><span style="color:#E5C07B;">8.</span><span style="color:#D19A66;"> **测试数据**</span><span style="color:#ABB2BF;">：测试需要的数据</span></span>
<span class="line"><span style="color:#E5C07B;">9.</span><span style="color:#D19A66;"> **测试环境**</span><span style="color:#ABB2BF;">：执行测试的环境信息</span></span>
<span class="line"><span style="color:#E5C07B;">10.</span><span style="color:#D19A66;"> **关联需求**</span><span style="color:#ABB2BF;">：关联的需求ID</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**测试用例设计原则：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **可读性**</span><span style="color:#ABB2BF;">：清晰易懂</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **可执行性**</span><span style="color:#ABB2BF;">：步骤可操作</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **可维护性**</span><span style="color:#ABB2BF;">：易于更新维护</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **可复用性**</span><span style="color:#ABB2BF;">：可以重复使用</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **可追溯性**</span><span style="color:#ABB2BF;">：能够追溯到需求</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="📊-测试流程" tabindex="-1"><a class="header-anchor" href="#📊-测试流程"><span>📊 测试流程</span></a></h2><h3 id="_8-缺陷管理流程是什么" tabindex="-1"><a class="header-anchor" href="#_8-缺陷管理流程是什么"><span>8. 缺陷管理流程是什么？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**缺陷生命周期：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **新建（New）**</span><span style="color:#ABB2BF;">：测试人员发现并报告缺陷</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **已分配（Assigned）**</span><span style="color:#ABB2BF;">：缺陷分配给开发人员</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **处理中（In Progress）**</span><span style="color:#ABB2BF;">：开发人员正在修复</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **已修复（Fixed）**</span><span style="color:#ABB2BF;">：开发人员完成修复</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **已验证（Verified）**</span><span style="color:#ABB2BF;">：测试人员验证修复</span></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#D19A66;"> **已关闭（Closed）**</span><span style="color:#ABB2BF;">：缺陷确认修复完成</span></span>
<span class="line"><span style="color:#E5C07B;">7.</span><span style="color:#D19A66;"> **重新打开（Reopened）**</span><span style="color:#ABB2BF;">：验证不通过，重新打开</span></span>
<span class="line"><span style="color:#E5C07B;">8.</span><span style="color:#D19A66;"> **拒绝（Rejected）**</span><span style="color:#ABB2BF;">：确认为非缺陷或重复</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**缺陷报告要素：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **缺陷ID**</span><span style="color:#ABB2BF;">：唯一标识符</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **缺陷标题**</span><span style="color:#ABB2BF;">：简洁明了的描述</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **严重程度**</span><span style="color:#ABB2BF;">：致命、严重、一般、轻微</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **优先级**</span><span style="color:#ABB2BF;">：立即解决、高、中、低</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#D19A66;"> **缺陷状态**</span><span style="color:#ABB2BF;">：当前状态</span></span>
<span class="line"><span style="color:#E5C07B;">6.</span><span style="color:#D19A66;"> **重现步骤**</span><span style="color:#ABB2BF;">：详细的重现步骤</span></span>
<span class="line"><span style="color:#E5C07B;">7.</span><span style="color:#D19A66;"> **实际结果**</span><span style="color:#ABB2BF;">：实际观察到的现象</span></span>
<span class="line"><span style="color:#E5C07B;">8.</span><span style="color:#D19A66;"> **预期结果**</span><span style="color:#ABB2BF;">：期望的结果</span></span>
<span class="line"><span style="color:#E5C07B;">9.</span><span style="color:#D19A66;"> **环境信息**</span><span style="color:#ABB2BF;">：操作系统、浏览器、版本等</span></span>
<span class="line"><span style="color:#E5C07B;">10.</span><span style="color:#D19A66;"> **附件**</span><span style="color:#ABB2BF;">：截图、日志、视频等</span></span>
<span class="line"><span style="color:#E5C07B;">11.</span><span style="color:#D19A66;"> **报告人**</span><span style="color:#ABB2BF;">：发现缺陷的人员</span></span>
<span class="line"><span style="color:#E5C07B;">12.</span><span style="color:#D19A66;"> **报告时间**</span><span style="color:#ABB2BF;">：发现缺陷的时间</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**缺陷严重程度定义：**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **致命（Critical）**</span><span style="color:#ABB2BF;">：系统崩溃、数据丢失、安全漏洞</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **严重（Major）**</span><span style="color:#ABB2BF;">：主要功能失效、性能严重下降</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **一般（Normal）**</span><span style="color:#ABB2BF;">：次要功能失效、界面显示问题</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **轻微（Minor）**</span><span style="color:#ABB2BF;">：界面细节问题、文字错误</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_9-什么是回归测试-如何进行回归测试" tabindex="-1"><a class="header-anchor" href="#_9-什么是回归测试-如何进行回归测试"><span>9. 什么是回归测试？如何进行回归测试？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**回归测试定义：**</span></span>
<span class="line"><span style="color:#ABB2BF;">回归测试是在软件修改后，重新执行之前通过的测试用例，以确保修改没有引入新的缺陷或导致原有功能失效。</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**回归测试策略：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **完全回归测试**</span><span style="color:#ABB2BF;">：执行所有测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 优点：最全面</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 缺点：成本高、耗时长</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：重大修改、核心模块修改</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **选择性回归测试**</span><span style="color:#ABB2BF;">：选择部分测试用例执行</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#D19A66;"> **基于风险的回归测试**</span><span style="color:#ABB2BF;">：优先测试高风险功能</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#D19A66;"> **基于影响的回归测试**</span><span style="color:#ABB2BF;">：测试受修改影响的功能</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#D19A66;"> **基于操作的回归测试**</span><span style="color:#ABB2BF;">：测试常用功能</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **渐进式回归测试**</span><span style="color:#ABB2BF;">：逐步增加测试范围</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 优点：平衡测试全面性和效率</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：持续集成环境</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**回归测试自动化：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **自动化回归测试的优势：**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 提高测试效率</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 减少人为错误</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 支持频繁回归</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 节省人力成本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **自动化回归测试策略：**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 核心功能自动化</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 高频使用功能自动化</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 稳定功能自动化</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 数据驱动测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**回归测试最佳实践：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#ABB2BF;"> 建立回归测试用例库</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#ABB2BF;"> 定期评审和更新测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#ABB2BF;"> 使用版本控制管理测试用例</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#ABB2BF;"> 建立自动化回归测试框架</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#ABB2BF;"> 集成到持续集成流程</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_10-什么是冒烟测试和-sanity-测试" tabindex="-1"><a class="header-anchor" href="#_10-什么是冒烟测试和-sanity-测试"><span>10. 什么是冒烟测试和 sanity 测试？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**冒烟测试（Smoke Testing）：**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **定义**</span><span style="color:#ABB2BF;">：在正式测试开始前，对软件的基本功能进行快速测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **目的**</span><span style="color:#ABB2BF;">：验证软件是否具备可测试性，防止测试资源浪费</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **范围**</span><span style="color:#ABB2BF;">：核心功能、主要流程</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **时间**</span><span style="color:#ABB2BF;">：每次构建后、正式测试前</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **特点**</span><span style="color:#ABB2BF;">：快速、简单、覆盖面小</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **示例**</span><span style="color:#ABB2BF;">：登录、注册、主要业务功能</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**健全性测试（Sanity Testing）：**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **定义**</span><span style="color:#ABB2BF;">：在回归测试中，对特定功能进行快速测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **目的**</span><span style="color:#ABB2BF;">：验证特定修改是否正常工作</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **范围**</span><span style="color:#ABB2BF;">：与修改相关的功能</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **时间**</span><span style="color:#ABB2BF;">：缺陷修复后、小范围修改后</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **特点**</span><span style="color:#ABB2BF;">：针对性强、深度有限</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **示例**</span><span style="color:#ABB2BF;">：修复的缺陷相关功能</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**区别：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **测试时机**</span><span style="color:#ABB2BF;">：冒烟测试在构建后，健全性测试在修改后</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **测试范围**</span><span style="color:#ABB2BF;">：冒烟测试覆盖核心功能，健全性测试覆盖修改相关功能</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **测试深度**</span><span style="color:#ABB2BF;">：冒烟测试较浅，健全性测试相对深入</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **测试目的**</span><span style="color:#ABB2BF;">：冒烟测试验证可测试性，健全性测试验证修改正确性</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="🛠️-测试工具" tabindex="-1"><a class="header-anchor" href="#🛠️-测试工具"><span>🛠️ 测试工具</span></a></h2><h3 id="_11-常用的测试管理工具有哪些" tabindex="-1"><a class="header-anchor" href="#_11-常用的测试管理工具有哪些"><span>11. 常用的测试管理工具有哪些？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**1. JIRA + Test Management**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 特点：与JIRA深度集成，支持敏捷测试</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 适用：敏捷开发团队，大中型企业</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 功能：测试计划、用例管理、缺陷跟踪、测试报告</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**2. 禅道（Zentao）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 特点：国产开源，一体化项目管理</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 适用：国内中小型企业，预算有限团队</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 功能：产品管理、项目管理、测试管理、缺陷管理</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**3. TestRail**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 特点：专业测试管理，强大报告功能</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 适用：专业测试团队，需要详细报告</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 功能：测试用例管理、测试计划、测试执行、自定义报告</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**4. qTest**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 特点：企业级测试管理，支持敏捷和瀑布</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 适用：大型企业，复杂测试流程</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 功能：需求管理、测试用例管理、测试执行、测试分析</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**5. Zephyr**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 特点：JIRA原生插件，轻量级测试管理</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 适用：使用JIRA的团队，敏捷开发团队</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 功能：测试用例管理、测试执行跟踪、实时仪表板</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_12-常用的自动化测试工具有哪些" tabindex="-1"><a class="header-anchor" href="#_12-常用的自动化测试工具有哪些"><span>12. 常用的自动化测试工具有哪些？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**Web自动化测试工具：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **Selenium**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 语言：Java、Python、C#、JavaScript等</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：开源、跨浏览器、跨平台</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：Web应用自动化测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **Playwright**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 语言：JavaScript、TypeScript、Python、Java、C#</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：现代化、高性能、支持多浏览器</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：现代Web应用自动化测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **Cypress**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 语言：JavaScript</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：快速、可靠、实时重载</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：前端应用自动化测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**接口测试工具：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **Postman**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：图形化界面、易用性强</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：接口调试、自动化测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **JMeter**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：开源、支持性能测试</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：接口性能测试、负载测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **SoapUI**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：专业Web服务测试</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：SOAP和REST接口测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**移动端测试工具：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **Appium**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：开源、跨平台</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：iOS和Android应用自动化测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **Android Studio**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：官方开发工具</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：Android应用测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **Xcode**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：官方开发工具</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：iOS应用测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**性能测试工具：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **JMeter**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：开源、功能全面</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：Web应用性能测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **LoadRunner**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：商业工具、功能强大</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：企业级性能测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **Gatling**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 特点：开源、高性能</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 适用：高并发性能测试</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="💼-面试技巧" tabindex="-1"><a class="header-anchor" href="#💼-面试技巧"><span>💼 面试技巧</span></a></h2><h3 id="_13-如何准备测试面试" tabindex="-1"><a class="header-anchor" href="#_13-如何准备测试面试"><span>13. 如何准备测试面试？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**面试前准备：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **复习基础知识**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 测试理论、测试方法、测试流程</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 缺陷管理、测试用例设计</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 自动化测试、性能测试</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **准备项目经验**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 梳理参与过的项目</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备项目介绍（背景、职责、成果）</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备技术难点和解决方案</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **了解公司信息**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 公司业务、产品、技术栈</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 公司文化、价值观</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 岗位要求、职责</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#D19A66;"> **准备常见问题**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 自我介绍</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 职业规划</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 离职原因</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 期望薪资</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**面试中表现：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#D19A66;"> **自我介绍**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 简洁明了，突出亮点</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 与岗位要求匹配</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 时间控制在2-3分钟</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#D19A66;"> **回答问题**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 先思考再回答</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 结构化回答（STAR法则）</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 举例说明，具体详细</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#D19A66;"> **提问环节**</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 准备有深度的问题</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 体现对岗位的兴趣</span></span>
<span class="line"><span style="color:#E5C07B;">   -</span><span style="color:#ABB2BF;"> 了解团队、项目、发展</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**STAR法则：**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **S（Situation）**</span><span style="color:#ABB2BF;">：情境，描述项目背景</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **T（Task）**</span><span style="color:#ABB2BF;">：任务，说明你的职责</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **A（Action）**</span><span style="color:#ABB2BF;">：行动，描述具体行动</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#D19A66;"> **R（Result）**</span><span style="color:#ABB2BF;">：结果，说明取得的成果</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">**常见问题示例：**</span></span>
<span class="line"><span style="color:#E5C07B;">1.</span><span style="color:#ABB2BF;"> 请介绍一下你最近参与的一个测试项目</span></span>
<span class="line"><span style="color:#E5C07B;">2.</span><span style="color:#ABB2BF;"> 你在项目中遇到的最大挑战是什么？如何解决的？</span></span>
<span class="line"><span style="color:#E5C07B;">3.</span><span style="color:#ABB2BF;"> 你是如何设计测试用例的？</span></span>
<span class="line"><span style="color:#E5C07B;">4.</span><span style="color:#ABB2BF;"> 你如何管理测试进度和质量？</span></span>
<span class="line"><span style="color:#E5C07B;">5.</span><span style="color:#ABB2BF;"> 你对自动化测试有什么经验？</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_14-测试工程师的职业发展路径是什么" tabindex="-1"><a class="header-anchor" href="#_14-测试工程师的职业发展路径是什么"><span>14. 测试工程师的职业发展路径是什么？</span></a></h3><div class="language-markdown line-numbers-mode" data-highlighter="shiki" data-ext="markdown" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-markdown"><span class="line"><span style="color:#D19A66;">**初级测试工程师（0-2年）**</span></span>
<span class="line"><span style="color:#E5C07B;">-</span><span style="color:#ABB2BF;"> 职责：执行测试用例、报告缺陷、编写</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div>`,35)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};